216:                                                          bool do_formatting) const {
217:   Http::HeaderTransforms transforms;
218: 
219:   for (const auto& [key, entry] : headers_to_add_) {
220:     if (do_formatting) {
221:       const std::string value = entry->formatter_->formatWithContext({}, stream_info);
222:       if (!value.empty() || entry->add_if_empty_) {
223:         switch (entry->append_action_) {
224:         case HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
225:           transforms.headers_to_append_or_add.push_back({key, value});
226:           break;
227:         case HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
228:           transforms.headers_to_overwrite_or_add.push_back({key, value});
